import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { LoadingSpinner } from '../../components/LoadingSpinner';
import { FileText, Building, Calendar, User, ArrowLeft, ExternalLink, Eye, Clock } from 'lucide-react';

const MOUDetails = () => {
  const { id } = useParams();
  const { api } = useAuth();
  const [mou, setMou] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchMOU();
  }, [id]);

  const fetchMOU = async () => {
    try {
      const response = await api.get(`/mou/${id}`);
      setMou(response.data);
    } catch (error) {
      console.error('Failed to fetch MOU:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <LoadingSpinner size="large" />
      </div>
    );
  }

  if (!mou) {
    return (
      <div className="text-center py-12">
        <h3 className="text-lg font-medium text-gray-900 mb-2">MOU not found</h3>
        <Link to="/mou" className="btn btn-primary">
